// Extract ticker from message like "$LMAT" or "$AAPL check this"
const message = $input.first().json.message?.text || '';

// Match $TICKER pattern (1-5 uppercase letters after $)
const match = message.match(/\$([A-Za-z]{1,5})/);

if (!match) {
  // Not a ticker message, stop the workflow
  return [];
}

const ticker = match[1].toUpperCase();
const chatId = $input.first().json.message?.chat?.id;
const fromUser = $input.first().json.message?.from?.first_name || 'Unknown';
const messageId = $input.first().json.message?.message_id;

// Check for deep dive flag
const deepDive = message.toLowerCase().includes('deep') || message.toLowerCase().includes('full');

return [{
  json: {
    ticker,
    chatId,
    fromUser,
    messageId,
    deepDive,
    rawMessage: message,
    timestamp: new Date().toISOString()
  }
}];

// Parse Claude Code JSON output
const sshOutput = $input.first().json.stdout || $input.first().json.stderr || '';

// Find the JSON block in the output
let result;
try {
  // Try to parse the last line (should be the JSON output)
  const lines = sshOutput.trim().split('\n');

  // Look for the JSON block - scan from end
  for (let i = lines.length - 1; i >= 0; i--) {
    const line = lines[i].trim();
    if (line.startsWith('{')) {
      // Found potential JSON start, try to find the end
      let jsonStr = lines.slice(i).join('\n');
      try {
        result = JSON.parse(jsonStr);
        break;
      } catch (e) {
        // Try just this line
        try {
          result = JSON.parse(line);
          break;
        } catch (e2) {
          continue;
        }
      }
    }
  }

  if (!result) {
    throw new Error('No JSON found in output');
  }
} catch (error) {
  // If parsing fails, create an error result
  result = {
    status: 'error',
    ticker: $('Extract Ticker').first().json.ticker,
    error: error.message,
    raw_output: sshOutput.substring(0, 2000)
  };
}

// Carry forward original context
result.chatId = $('Extract Ticker').first().json.chatId;
result.messageId = $('Extract Ticker').first().json.messageId;
result.fromUser = $('Extract Ticker').first().json.fromUser;
result.deepDive = $('Extract Ticker').first().json.deepDive;

return [{ json: result }];

// Build the Telegram message from Claude's research output
const data = $input.first().json;

// Use the one_pager if available, otherwise build from parts
let message;

if (data.one_pager) {
  message = data.one_pager;
} else {
  // Fallback: build from structured data
  const verdict = data.verdict || 'UNKNOWN';
  const verdictEmoji = {
    'BUY': '🟢',
    'HOLD': '🟡', 
    'PASS': '🔴',
    'DEEP_DIVE': '🔵'
  }[verdict] || '⚪';

  message = `${verdictEmoji} **$${data.ticker} — ${data.company}**\n`;
  message += `**Verdict: ${verdict}** (${data.confidence} confidence)\n\n`;
  message += `${data.thesis || 'No thesis generated.'}\n\n`;

  if (data.key_metrics) {
    message += `**Key Metrics:**\n`;
    const m = data.key_metrics;
    if (m.revenue_latest) message += `• Revenue: ${m.revenue_latest}\n`;
    if (m.revenue_growth) message += `• Rev Growth: ${m.revenue_growth}\n`;
    if (m.net_margin) message += `• Net Margin: ${m.net_margin}\n`;
    if (m.pe_ratio) message += `• P/E: ${m.pe_ratio}\n`;
    if (m.fcf_yield) message += `• FCF Yield: ${m.fcf_yield}\n`;
    message += `\n`;
  }

  if (data.insider_sentiment) {
    message += `**Insider Sentiment:** ${data.insider_sentiment}\n\n`;
  }

  if (data.catalysts && data.catalysts.length > 0) {
    message += `**Catalysts:**\n`;
    data.catalysts.forEach(c => { message += `• ${c}\n`; });
    message += `\n`;
  }

  if (data.risks && data.risks.length > 0) {
    message += `**Risks:**\n`;
    data.risks.forEach(r => { message += `• ${r}\n`; });
  }
}

// Telegram has a 4096 char limit
if (message.length > 4000) {
  message = message.substring(0, 3950) + '\n\n_(truncated — full report saved)_';
}

return [{
  json: {
    ...data,
    telegramMessage: message
  }
}];

